/**
 * MedX stack layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Vertical and horizontal stack gap utilities.
 */
const STACK_TOKENS = Object.freeze({
  primary: { value: "layout-stack-primary", scope: "layout" },
  secondary: { value: "layout-stack-secondary", scope: "layout" },
  muted: { value: "layout-stack-muted", scope: "layout" },
  accent: { value: "layout-stack-accent", scope: "layout" },
  surface: { value: "layout-stack-surface", scope: "layout" },
});

const STACK_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const STACK_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const stackRegistry = new Map();
const STACK_listeners = new Set();
let STACK_seq = 0;

function createStackId(prefix = "medx-layout-stack") {
  STACK_seq += 1;
  return `${prefix}-${STACK_seq}`;
}

function registerStack(config = {}) {
  const entryId = config.id ?? createStackId();
  const preset = STACK_PRESETS[config.preset ?? "default"] ?? STACK_PRESETS.default;
  const token = STACK_TOKENS[config.token ?? preset.token] ?? STACK_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: STACK_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  stackRegistry.set(entryId, entry);
  notifyStackListeners("register", entry);
  return entry;
}

function updateStack(id, patch = {}) {
  const entry = stackRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyStackListeners("update", entry);
  return entry;
}

function resolveStack(id) {
  const entry = stackRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listStackEntries(filter = {}) {
  let items = Array.from(stackRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onStackEvent(listener) {
  STACK_listeners.add(listener);
  return () => STACK_listeners.delete(listener);
}

function notifyStackListeners(type, entry) {
  for (const listener of STACK_listeners) {
    try {
      listener({ type, entry, registrySize: stackRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:stack] listener error", err.message);
    }
  }
}

function getStackMetrics() {
  const items = listStackEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(STACK_TOKENS).length,
    presets: Object.keys(STACK_PRESETS).length,
  };
}

async function runMedxStack() {
  console.log("[medx:ui:layout:stack] runtime initialized");
  console.log(`[medx:ui:layout:stack] tokens=${Object.keys(STACK_TOKENS).length} presets=${Object.keys(STACK_PRESETS).length}`);

  const events = [];
  onStackEvent((e) => events.push(e.type));

  const domains = Object.keys(STACK_SUPPLY_CHAIN);
  const presets = Object.keys(STACK_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerStack({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/stack" },
    });
  }

  const first = listStackEntries()[0];
  if (first) updateStack(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getStackMetrics();
  const resolved = first ? resolveStack(first.id) : null;

  console.log(`[medx:ui:layout:stack] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:stack] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:stack] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:stack] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:stack] bootstrap complete");
}

module.exports = runMedxStack;
